def get_data_with_access_control(user_role):
    """Return data based on user permissions."""
    if user_role == 'admin':
        # Full access to all data
        return df

    elif user_role == 'analyst':
        # Remove highly sensitive columns
        return df.drop(columns=['ssn', 'salary', 'medical_history'])

    elif user_role == 'viewer':
        # Aggregated data only (no individual records)
        return df.groupby('department').agg({
            'revenue': 'sum',
            'employee_count': 'count'
        })

    else:
        # No access
        raise PermissionError(f"Role '{user_role}' has no data access")

# Usage
analyst_data = get_data_with_access_control('analyst')
viewer_data = get_data_with_access_control('viewer')
